import 'package:shared_preferences/shared_preferences.dart';
class SessionStore{static const _userId='userId',_nickname='nickname';Future<String?> userId()async=>(await SharedPreferences.getInstance()).getString(_userId);Future<String?> nickname()async=>(await SharedPreferences.getInstance()).getString(_nickname);Future<void> save({required String userId,required String nickname})async{final p=await SharedPreferences.getInstance();await p.setString(_userId,userId);await p.setString(_nickname,nickname);}Future<void> clear()async{final p=await SharedPreferences.getInstance();await p.remove(_userId);await p.remove(_nickname);}}
